import React, { useState, useEffect, useMemo } from 'react';
import axios from 'axios';

function App() {
  const [activePage, setActivePage] = useState('market');
  const [walletBalance, setWalletBalance] = useState(10000);
  const [holdings, setHoldings] = useState([]);
  const [marketPrices, setMarketPrices] = useState({});
  const [myTicker, setMyTicker] = useState("");
  const [newPrice, setNewPrice] = useState("");
  const [token] = useState("YOUR_JWT_TOKEN_HERE");

  useEffect(() => {
    const ws = new WebSocket('ws://localhost:5000', token);

    ws.onmessage = (event) => {
      const data = JSON.parse(event.data);
      if (data.type === "TICKER_UPDATE") {
        setMarketPrices(prev => {
          const oldPrice = prev[data.payload.ticker]?.price || 0;
          const newPriceVal = data.payload.price;
          const direction = newPriceVal > oldPrice ? 'up' : newPriceVal < oldPrice ? 'down' : 'neutral';
          return {
            ...prev,
            [data.payload.ticker]: { price: newPriceVal, direction }
          };
        });
      }
    };

    return () => ws.close();
  }, [token]);

  const netWorth = useMemo(() => {
    const assetsValue = holdings.reduce((total, stock) => {
      const currentPrice = marketPrices[stock.ticker]?.price || 0;
      return total + (stock.amount * currentPrice);
    }, 0);
    return walletBalance + assetsValue;
  }, [walletBalance, holdings, marketPrices]);

  const handleBuy = async (ticker) => {
    try {
      const response = await axios.post('http://localhost:5000/api/buy', 
        { ticker, amount: 1 }, 
        { headers: { Authorization: `Bearer ${token}` } }
      );
      setWalletBalance(response.data.balance);
      setHoldings(response.data.holdings);
    } catch (error) {
      alert("Ошибка при покупке.");
    }
  };

  const handleUpdatePrice = async () => {
    try {
      await axios.patch('http://localhost:5000/api/stocks/update-price', 
        { ticker: myTicker, newPrice: parseFloat(newPrice) }, 
        { headers: { Authorization: `Bearer ${token}` } }
      );
      setNewPrice("");
    } catch (error) {
      alert("Только владелец может менять цену (403 Forbidden)");
    }
  };

  const getPriceStyle = (direction) => ({
    fontSize: '1.8rem',
    fontWeight: 'bold',
    color: direction === 'up' ? '#2ecc71' : direction === 'down' ? '#e74c3c' : '#2c3e50',
    backgroundColor: direction === 'up' ? 'rgba(46, 204, 113, 0.1)' : direction === 'down' ? 'rgba(231, 76, 60, 0.1)' : 'transparent',
    padding: '5px',
    borderRadius: '5px'
  });

  return (
    <div style={styles.container}>
      <header style={styles.header}>
        <div>
          <h1 style={{ margin: 0 }}>PEX Terminal</h1>
          <p style={{ color: '#7f8c8d' }}>Инвестируй в людей</p>
        </div>
        <div style={styles.statsContainer}>
          <div style={styles.statBox}>
            <span style={styles.label}>CASH</span>
            <span style={styles.value}>${walletBalance.toFixed(2)}</span>
          </div>
          <div style={styles.statBox}>
            <span style={styles.label}>NET WORTH</span>
            <span style={{ ...styles.value, color: '#3498db' }}>${netWorth.toFixed(2)}</span>
          </div>
        </div>
      </header>

      <nav style={styles.navbar}>
        <button onClick={() => setActivePage('market')} style={activePage === 'market' ? styles.navBtnActive : styles.navBtn}>📊 Рынок</button>
        <button onClick={() => setActivePage('portfolio')} style={activePage === 'portfolio' ? styles.navBtnActive : styles.navBtn}>💼 Портфель</button>
      </nav>

      <main style={styles.content}>
        {activePage === 'market' && (
          <section>
            <h2 style={styles.pageTitle}>Биржевые котировки (Real-time)</h2>
            <div style={styles.grid}>
              {Object.entries(marketPrices).map(([ticker, data]) => (
                <div key={ticker} style={styles.marketCard}>
                  <div style={styles.cardBadge}>LIVE</div>
                  <h3>${ticker}</h3>
                  <div style={getPriceStyle(data.direction)}>
                    ${data.price.toFixed(2)}
                    <span>{data.direction === 'up' ? '▲' : data.direction === 'down' ? '▼' : ''}</span>
                  </div>
                  <button onClick={() => handleBuy(ticker)} style={styles.buyButton}>Купить</button>
                </div>
              ))}
            </div>
          </section>
        )}

        {activePage === 'portfolio' && (
          <section>
            <h2 style={styles.pageTitle}>Личный кабинет</h2>
            
            <div style={styles.managementCard}>
              <h3>Управление своей акцией</h3>
              <input 
                style={styles.input}
                placeholder="Ваш тикер (напр. DEV)" 
                value={myTicker} 
                onChange={(e) => setMyTicker(e.target.value.toUpperCase())}
              />
              <input 
                style={styles.input}
                type="number" 
                placeholder="Новая цена" 
                value={newPrice} 
                onChange={(e) => setNewPrice(e.target.value)}
              />
              <button onClick={handleUpdatePrice} style={styles.updateButton}>Обновить цену для всех</button>
            </div>

            <div style={styles.tableWrapper}>
              <table style={styles.table}>
                <thead>
                  <tr><th>Тикер</th><th>Кол-во</th><th>Цена</th><th>Итого</th></tr>
                </thead>
                <tbody>
                  {holdings.map(h => (
                    <tr key={h.ticker}>
                      <td>${h.ticker}</td>
                      <td>{h.amount}</td>
                      <td>${(marketPrices[h.ticker]?.price || 0).toFixed(2)}</td>
                      <td>${(h.amount * (marketPrices[h.ticker]?.price || 0)).toFixed(2)}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </section>
        )}
      </main>
    </div>
  );
}

const styles = {
  container: { backgroundColor: '#f9f9fb', minHeight: '100vh', fontFamily: 'sans-serif' },
  header: { display: 'flex', justifyContent: 'space-between', padding: '20px 50px', backgroundColor: '#fff', borderBottom: '1px solid #ddd' },
  statsContainer: { display: 'flex', gap: '20px' },
  statBox: { backgroundColor: '#f1f3f5', padding: '10px', borderRadius: '8px', minWidth: '120px' },
  label: { fontSize: '0.7rem', color: '#666', fontWeight: 'bold' },
  value: { fontSize: '1.1rem', fontWeight: 'bold' },
  navbar: { display: 'flex', justifyContent: 'center', gap: '10px', padding: '20px' },
  navBtn: { padding: '10px 20px', borderRadius: '20px', border: '1px solid #ddd', cursor: 'pointer' },
  navBtnActive: { padding: '10px 20px', borderRadius: '20px', border: 'none', backgroundColor: '#2c3e50', color: '#fff', cursor: 'pointer' },
  content: { padding: '0 50px' },
  pageTitle: { borderLeft: '4px solid #3498db', paddingLeft: '10px' },
  grid: { display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(200px, 1fr))', gap: '20px' },
  marketCard: { position: 'relative', backgroundColor: '#fff', padding: '20px', borderRadius: '12px', textAlign: 'center', border: '1px solid #eee' },
  cardBadge: { position: 'absolute', top: '10px', right: '10px', backgroundColor: '#e74c3c', color: '#fff', fontSize: '0.6rem', padding: '2px 5px', borderRadius: '4px' },
  buyButton: { width: '100%', marginTop: '10px', padding: '10px', backgroundColor: '#2ecc71', color: '#fff', border: 'none', borderRadius: '8px', cursor: 'pointer' },
  managementCard: { backgroundColor: '#fff', padding: '20px', borderRadius: '12px', marginBottom: '20px', border: '1px solid #ddd' },
  input: { padding: '10px', marginRight: '10px', borderRadius: '4px', border: '1px solid #ccc' },
  updateButton: { padding: '10px 20px', backgroundColor: '#3498db', color: '#fff', border: 'none', borderRadius: '4px', cursor: 'pointer' },
  tableWrapper: { backgroundColor: '#fff', padding: '20px', borderRadius: '12px' },
  table: { width: '100%', textAlign: 'left', borderCollapse: 'collapse' }
};

export default App;
